package com.hospital.management.controller.admin;import com.hospital.management.model.Patient;import com.hospital.management.service.*;import com.hospital.management.service.impl.PatientServiceImpl;import javax.servlet.*;import javax.servlet.annotation.WebServlet;import javax.servlet.http.*;import java.io.IOException;import java.util.Optional;
@WebServlet("/admin/patients/view")public class PatientViewServlet extends HttpServlet{private final PatientService service;public PatientViewServlet(){this(new PatientServiceImpl());}public PatientViewServlet(PatientService s){service=s;}protected void doGet(HttpServletRequest q,HttpServletResponse r)throws ServletException,IOException{Long id=Form.id(q.getParameter("id"));if(id==null){r.sendError(400);return;}Optional<Patient>p=service.getPatient(id);if(p.isEmpty()){r.sendError(404);return;}q.setAttribute("patient",p.get());q.getRequestDispatcher("/WEB-INF/views/admin/patients/view.jsp").forward(q,r);}}
